solution:
function sumWithForOf(nums) {
  // start the accumulator at zero
  let total = 0;
  // for...of yields each value directly — no index variable needed
  for (const value of nums) {
    // accumulate each value
    total += value;
  }
  // return the final sum
  return total;
}

