solution:
function flattenOne(arrays) {
  const result = [];
  // outer loop: each item in arrays is itself an array
  for (const subArray of arrays) {
    // inner loop: each element of the sub-array
    for (const element of subArray) {
      result.push(element);
    }
  }
  return result;
}
